pub fn shm_create(size: usize) -> usize {
    let num = (size + PAGE_SIZE - 1) / PAGE_SIZE;
    let mut manager = SHM_MANAGER.lock();
    let key = manager.next_key;
    manager.map.insert(key, Shm::new(num));
    manager.next_key += 1;
    key
}

